        const coordinates = oldDoc.coordinates;
        return fetch('http://myserver.com/api/countryByCoordinates/' + coordinates + '/')
          .then(response => {
            const response = response.json();
            oldDoc.senderCountry = response;
            return oldDoc;
          });
      }
    }
  }
});
